// Vanilla - NetHandlerLoginClient.java enables compression:
public void handleEnableCompression(S03PacketEnableCompression packetIn) {
    if (!this.netManager.isLocalChannel()) {
        this.netManager.setCompressionTreshold(packetIn.getCompressionTreshold());
    }
}

// Aqua 13 - Disabler can intercept the threshold value:
// The compression threshold affects how NetworkManager frames packets:
// After S03, every packet has: [VarInt: uncompressed_length][VarInt: packet_id][data...]
// If uncompressed_length < threshold, the packet body is raw (no compression)
// If uncompressed_length >= threshold, the packet body is zlib-compressed

// Vanilla S03PacketEnableCompression definition:
public class S03PacketEnableCompression implements Packet<INetHandlerLoginClient> {
    private int compressionTreshold;

    public S03PacketEnableCompression() {}
    public S03PacketEnableCompression(int tresholdIn) {
        this.compressionTreshold = tresholdIn;
    }

    public void readPacketData(PacketBuffer buf) throws IOException {
        this.compressionTreshold = buf.readVarIntFromBuffer();
    }

    public int getCompressionTreshold() {
        return this.compressionTreshold;
    }
}

// NetworkManager.java - how compression is applied:
public void setCompressionTreshold(int treshold) {
    if (treshold >= 0) {
        // Add zlib compressor/decompressor to the Netty pipeline
        this.channel.pipeline().addBefore("decoder", "decompress", new NettyCompressionDecoder(treshold));
        this.channel.pipeline().addBefore("encoder", "compress", new NettyCompressionEncoder(treshold));
    } else {
        // Remove compression handlers if they exist
        if (this.channel.pipeline().get("decompress") != null) {
            this.channel.pipeline().remove("decompress");
        }
        if (this.channel.pipeline().get("compress") != null) {
            this.channel.pipeline().remove("compress");
        }
    }
    this.compressionTreshold = treshold;
}

